React Native Web 把 ScrollView 渲染为带 overflow:auto 的 div，不是 window 整页滚动。所以 page.evaluate(() => window.scrollBy(0, 350)) 在 OneKey 里完全没效果。

通用 helper：
```js
function findScrollContainer(anchor) {
  let el = anchor;
  while (el && el !== document.body) {
    const cs = getComputedStyle(el);
    if ((cs.overflowY === 'auto' || cs.overflowY === 'scroll' || cs.overflowY === 'overlay')
        && el.scrollHeight > el.clientHeight + 5) return el;
    el = el.parentElement;
  }
  // 兜底：全页找最大可滚 div
  let best = null, bestArea = 0;
  for (const cand of document.querySelectorAll('div')) {
    const cs = getComputedStyle(cand);
    if ((cs.overflowY === 'auto' || cs.overflowY === 'scroll') && cand.scrollHeight > cand.clientHeight + 5) {
      const r = cand.getBoundingClientRect();
      if (r.width * r.height > bestArea) { bestArea = r.width * r.height; best = cand; }
    }
  }
  return best;
}
findScrollContainer(anchor).scrollBy(0, 350);
```

触发场景：所有 OneKey 桌面端长列表滚动；Extension/Web 端同理。

JS DOM 规范里 SVGElement 不继承 HTMLElement.click()。在 OneKey 桌面端常遇到：APY icon 旁的小 svg、nav-header-back 等图标按钮、tab 图标。

现象：脚本 `await page.evaluate(() => { const svg = ...; svg.click(); })` 抛 `svg.click is not a function`。

通用 helper：
```js
async function safeClickElement(page, queryFn) {
  const pos = await page.evaluate(queryFn); // returns {x, y, width, height}
  if (!pos) throw new Error('not found');
  await page.mouse.click(pos.x + pos.width/2, pos.y + pos.height/2);
}
```

触发场景：所有「图标按钮」点击——尤其 nav-header-* / 关闭按钮 / icon-btn 类。

原 saveSteps 只依赖启动时一次性 mkdir，运行中如果目录被外部删除，会抛 ENOENT crash recorder。

已在 src/recorder/listen.mjs 加防御：
```js
function saveSteps() {
  try { mkdirSync(RECORDING_DIR, { recursive: true }); } catch {}
  writeFileSync(`${RECORDING_DIR}/steps.json`, ...);
}
```

触发场景：保护 recorder 不被外部 rm 误杀；同理写其他长期运行的 writeFileSync 都建议加 mkdir 防御。

DeFi 质押/赎回流程中，每一步操作弹出签名弹窗：
1. 主页面点「授权/认购/赎回」(page-footer-confirm) → 弹出 APP-Modal-Screen 弹窗
2. 弹窗内底部也有 page-footer-confirm 按钮（文本是「确认」）
3. 如果脚本继续点 document.querySelector('[data-testid="page-footer-confirm"]')，可能点到的是**主页面**的 button（被弹窗遮挡但 DOM 里在），结果**关闭弹窗**而不是确认交易

现象：用户报「当时没有点击确认就把弹窗给关了」。

**修复**：
```js
async function clickModalConfirm(page) {
  const modal = document.querySelector('[data-testid="APP-Modal-Screen"]');
  if (!modal) return false;
  // 只在 modal 子树内找 confirm，取最靠底部的（弹窗 footer）
  const candidates = [...modal.querySelectorAll('[data-testid="page-footer-confirm"]')];
  candidates.sort((a, b) => b.getBoundingClientRect().y - a.getBoundingClientRect().y);
  ...
}
```

配套：用 `waitForModalClose` 等弹窗消失确认交易已提交。

触发场景：所有「主页面点按钮 → 弹出签名弹窗 → 弹窗里点确认」流程。

CDP 实探（K-126 起替代之前 K-106 的猜测）：

Lista USDT 详情页 (file:///defi/EarnProtocolDetails?...) 上的「历史记录」按钮：
- testid: `staking-has-content-btn`
- 位置: 视口宽度 1363 时 x=1177-1212 y=127-133 大小 100×32
- textContent: '历史记录'（带 clock icon）

**坑**：同一 testid 在页面上有 2 个实例：
- 实例 A: x=1177-1212 (右上角，要点的) ⭐
- 实例 B: x=891 (另一处，不点)

**正确定位**：
```js
for (const el of document.querySelectorAll('[data-testid="staking-has-content-btn"]')) {
  if (el.textContent?.trim() !== '历史记录') continue;
  const r = el.getBoundingClientRect();
  if (r.x > window.innerWidth / 2) {
    // 这才是右上角那个
    return r;
  }
}
```

**注意**：之前 K-106 推测的 `redemption-history-btn` 和 `staking-render-history-right-button-btn` 都不存在。K-106 已被本条修正。

触发场景：DeFi 渠道详情页跳转到历史记录页。

DeFi 持仓页（点 Lista 详情页右上「持仓 >」跳到这里）：

**URL**: `file:///defi?mode=earn&tab=portfolio`

**每行 testid**: `earn-portfolio-item-<ProtocolName>`
- earn-portfolio-item-Morpho
- earn-portfolio-item-Pendle
- earn-portfolio-item-Everstake
- earn-portfolio-item-Stakefish
- earn-portfolio-item-Lista
- earn-portfolio-item-Ethena
- earn-portfolio-item-Lido

**每行右侧的「管理」按钮**：
- 标签：`SPAN` text='管理'
- 位置 (viewport 1363)：x=1229, y 跟 row 不严格对齐
- 大小：28×20
- **没有 data-testid** ❗

**定位策略**：
```js
async function clickManageForProtocol(page, protocol) {
  // 1. 滚 portfolio-item 进视口
  await page.evaluate((p) => {
    document.querySelector(`[data-testid="earn-portfolio-item-${p}"]`)?.scrollIntoView({block: 'center'});
  }, protocol);
  await sleep(800);
  // 2. 取 protocol row 中心 y
  const target = await page.evaluate((p) => {
    const lr = document.querySelector(`[data-testid="earn-portfolio-item-${p}"]`).getBoundingClientRect();
    const cy = lr.y + lr.height/2;
    const items = [];
    for (const el of document.querySelectorAll('*')) {
      if ((el.textContent||'').trim() !== '管理' || el.children.length !== 0) continue;
      const r = el.getBoundingClientRect();
      if (r.x > 1000 && r.width > 0) items.push({r, dy: r.y + r.height/2 - cy});
    }
    items.sort((a,b) => Math.abs(a.dy) - Math.abs(b.dy));
    const r = items[0].r;
    return { x: r.x + r.width/2, y: r.y + r.height/2 };
  }, protocol);
  await page.mouse.click(target.x, target.y);
}
```

**点击后**：跳到 `file:///ManagePosition?networkId=...&provider=<protocol>&vault=...`，弹出 modal 含「认购/赎回」tab。

触发场景：写任何 DeFi 渠道（Lista/Pendle/Morpho/Lido 等）的赎回/管理脚本时复用此 helper。

点击我的持仓页里 Lista（或其他协议）行的「管理」按钮后，会跳到 ManagePosition 弹出 modal。

**URL**: `file:///ManagePosition?networkId=evm--<chainId>&symbol=<TOKEN>&provider=<protocol>&vault=<address>`

**modal 结构**：
- 顶部 tab: 「认购」(x≈390, y≈140, width<100) | 「赎回」(x≈441, y≈140)
- 切到「赎回」后：
  - 金额输入框：`<input data-testid="amount-input-input-element-input" placeholder="0">` x=382 y=216 width=486
  - 「最大」快捷按钮：text='最大' x≈940 y≈268
  - 预估收益区/手续费/其他信息（具体根据协议）
  - 底部按钮：`[data-testid="page-footer-confirm"]` text='赎回' x≈920 y≈664
- 点底部「赎回」→ 弹签名 modal（层级在原 modal 之上）→ modal 内点「确认」
- 签名 modal 关闭后 → 跳到 `/defi?mode=earn&tab=portfolio`（持仓列表）

**通用 helper 思路**：
```js
async function executeRedeem(page, amount) {
  // 切到赎回 tab
  await clickInModalByText(page, '赎回', { yMax: 200 });
  // 输入金额
  await page.locator('[data-testid="amount-input-input-element-input"]').first().pressSequentially(amount);
  // 底部赎回按钮
  await clickModalFooterConfirm(page);
  // 签名 modal 内确认
  await clickModalFooterConfirm(page);  // 第二次 = 签名 modal 的 confirm
  // 等所有 modal 关闭
  await waitForAllModalsClose(page);
}
```

触发场景：所有 DeFi 渠道赎回/认购脚本（Lista/Pendle/Morpho/Lido 等共用）。

本会话踩过多次：脚本静态 probe 时能找到按钮（如 Lista 详情页右上「历史记录」/「持仓」），但 dashboard 跑到那一步时报「找不到」。

根因：前一个 case 完成后（如 DEFI-LISTA-004 modal 关闭，DEFI-LISTA-005 历史 modal 关闭），页面正在过渡（modal 淡出 + 主页面重新挂载 + React 重渲染），按钮可能：
- 暂时在 DOM 但 width/height = 0
- 还没挂上 onClick handler
- 位置临时偏移

**修复模板**：
```js
let pos = null;
let lastDiag = null;
for (let attempt = 0; attempt < 10; attempt++) {
  const result = await page.evaluate(() => { /* 查找逻辑 + 诊断信息 */ });
  lastDiag = result.diag;
  if (result.pos) { pos = result; break; }
  await sleep(500);
}
if (!pos) throw new Error(`找不到 X（10 retries × 500ms，诊断：${JSON.stringify(lastDiag)}）`);
```

**关键**：retry 内部要带**诊断信息**（candidates count / testid 实例数 / 文本节点数），帮助下次失败时快速定位真实原因（是元素不存在 vs 在 DOM 但不可点 vs 时机问题）。

**触发场景**：所有相邻 step / case 之间的页面元素查找，特别是涉及 modal 开关、URL 路由跳转、tab 切换的场景。

本会话踩过：`readSubscriptionValueUsd` 用 querySelectorAll + 文本 `^\$([\d.]+)$` 模糊找页面所有 $XX.XX，结果撞到了别处的 $36.74（资产列表里另一个代币的价格），不是输入框下方的 $99.96。

OneKey DeFi 详情页有几十个 $XX.XX 文本元素：
- 「热门」section USDT/USDC/ETH 卡片价格
- 「所有资产」列表里每行的 24h 涨幅金额
- TVL $1.92M
- 输入框下方的认购价值 $99.96 ⭐ 真正想要的

**修复模板**：
```js
// ❌ 错的：全页查找
for (const el of document.querySelectorAll('span, div')) {
  if (el.textContent?.trim().match(/^\$([\d.]+)$/)) return el;
}

// ✅ 对的：用 anchor（输入框）+ 相对位置过滤
const input = document.querySelector('[data-testid="amount-input-input-element-input"]');
const ir = input.getBoundingClientRect();
const candidates = [];
for (const el of document.querySelectorAll('span, div, p')) {
  const m = el.textContent?.trim().match(/^\$([\d.,]+)$/);
  if (!m || el.children.length !== 0) continue;
  const r = el.getBoundingClientRect();
  const dx = r.x - ir.x;
  const dy = r.y - ir.y;
  // 在 input 下方紧邻区域：dy 10-80, |dx| <= input.width + 200
  if (dy >= 10 && dy <= 80 && Math.abs(dx) <= ir.width + 200) {
    candidates.push({ value: parseFloat(m[1].replace(/,/g, '')), dy });
  }
}
candidates.sort((a, b) => a.dy - b.dy);  // 取最贴近的
return candidates[0]?.value;
```

**通用原则**：任何「读取某 anchor 旁边的某文本」类操作，必须基于 anchor 的 BoundingClientRect 做相对位置过滤。不要全页 querySelector 文本匹配。

**触发场景**：读输入框下的法币价值；读按钮旁的余额；读 row 内某列的值；任何位置敏感的文本读取。

本会话踩过：DEFI-LISTA-005 末尾用 `el.click()` 关历史 modal，但 nav-header-back/close 是 SVG（K-115：SVG 没有 HTMLElement.click()），所以 click 没生效。modal 没关 → DEFI-LISTA-006 找「持仓 >」按钮被 modal 遮挡 → 全测试失败。

**双保险关 modal 策略**：

```js
// (1) 在结束 modal 的 case 末尾，retry 关闭直到 modal 真的消失
async function closeTopModalUntilGone(page, maxRetries = 6) {
  for (let i = 0; i < maxRetries; i++) {
    const cnt = await page.evaluate(() => document.querySelectorAll('[data-testid="APP-Modal-Screen"]').length);
    if (cnt === 0) return true;
    const pos = await page.evaluate(() => {
      const modals = [...document.querySelectorAll('[data-testid="APP-Modal-Screen"]')];
      const top = modals[modals.length - 1];
      for (const sel of ['nav-header-back', 'nav-header-close', 'page-close-trigger']) {
        const el = top.querySelector(`[data-testid="${sel}"]`) || document.querySelector(`[data-testid="${sel}"]`);
        if (el) {
          const r = el.getBoundingClientRect();
          if (r.width > 0) return { x: r.x + r.width / 2, y: r.y + r.height / 2 };
        }
      }
      return null;
    });
    if (pos) await page.mouse.click(pos.x, pos.y);
    else await page.keyboard.press('Escape').catch(() => {});
    await sleep(800);
  }
  return false;
}

// (2) 在下一个 case 的 Step 0 加「兜底清 modal」防御（即使上一个 case 关不掉也能自救）
await sStep(page, t, 'Step 0: 前置清理遗留 modal', async () => {
  await closeTopModalUntilGone(page, 6);
});
```

**触发场景**：所有 modal 相关 case 衔接处（DeFi/Swap/Send/Sign Confirm 等）。

本会话踩过：用户在 Dashboard 只勾选了 DEFI-LISTA-005 + 006，跑的时候页面在 Wallet 主页，结果 005 找不到 Lista 详情页右上的「历史记录」按钮 → 全失败。

**根因**：脚本设计成顺序依赖（001 → 002 → ... → 006），每个 case 假设上一个留下了正确状态。但 Dashboard 允许用户**任意勾选子集**，比如只跑 005+006、只跑 003、单跑某个 case 等。

**强制规则**（写进任何 .test.mjs 都要遵守）：

1. **每个 case 开头必须有 `Step 0: 前置` 步骤**，调用幂等的 `goTo<目标页>(page)` helper
2. **导航 helper 必须幂等**：检查 URL/已有元素，已经在目标页面就直接返回，避免重复点击
3. **状态依赖**：如果 case 需要某种 UI 中间状态（如输入框已填值、已展开某个 section），必须检查 → 没有就构造它

**模板**：
```js
async function goToTargetPage(page) {
  // 0. 幂等检查
  const alreadyThere = await page.evaluate(() => {
    return location.href.includes('TargetPath') && document.querySelectorAll('[data-testid="APP-Modal-Screen"]').length === 0;
  });
  if (alreadyThere) return;
  // 1. 关闭遗留 modal（page.mouse.click 不要用 el.click() — K-115）
  // 2. 点导航入口 → 验证页面加载完成
}

async function testFooXxx001(page) {
  // ⭐ 每个 case 都有 Step 0
  await sStep(page, t, 'Step 0: 前置 — 确保在目标页', async () => {
    await goToTargetPage(page);
  });
  // ... 正常步骤
}
```

**触发场景**：所有 Dashboard 可单跑的 case；新生成测试脚本时一定要 review 是否每个 case 都有 Step 0 前置；review 时如果发现 case 不能独立跑（依赖前一个 case 的状态），必须补 Step 0。

OneKey DeFi 我的持仓页有多行（Lista / Pendle / Morpho / Lido 等），**每行都有独立的「管理」按钮**。但**「管理」按钮不在 row 的 boundingRect 内**（DOM 上是独立列），所以 contains 检测无效，只能靠位置匹配。

关键发现（CDP 实证）：
- portfolio 卡片实际 = 协议名 row（y=405, h=48） + 下方信息行（含「管理」按钮 y=518）
- 「管理」按钮**在 row 下方**（dy 通常 +60~+130）
- 协议之间的「管理」按钮垂直间距约 60~100px

**之前踩坑**：用 `|dy| 最近` 选最近按钮 → 撞到了上方相邻协议的「管理」（dy=-76 比 dy=+113 绝对值小）。

**正确模板**：
```js
// dy 必须在 [-20, 150] 范围内（≥ -20 避免抓到上方相邻协议；≤ 150 卡片高度上限）
// 取 dy 最小的（最贴近 row 下方）
for (const el of document.querySelectorAll('span, div, button')) {
  if (el.textContent?.trim() !== '管理' || el.children.length !== 0) continue;
  const r = el.getBoundingClientRect();
  if (r.width === 0 || r.x < 1000) continue;  // x>1000 限定右侧操作列
  const dy = r.y + r.height / 2 - listaCY;
  if (dy >= -20 && dy <= 150) items.push({ x, y, dy });
}
items.sort((a, b) => a.dy - b.dy);  // 取最小 dy（按钮在 row 下方紧贴）
```

**通用原则**：当目标按钮**在 row 下方**而非内部时：
1. dy 必须 ≥ -20（防上方撞名）
2. dy ≤ 150（卡片高度上限，避免抓到下方协议）
3. 排序按 **dy 升序**（取最小正值），不是按 |dy|

**点击后必须 URL/状态验证**（确保选对了 row 对应的协议）。

**触发场景**：所有「在多 row 列表里点 row 下方/下行按钮」的场景 — DeFi 持仓页、产品卡片底部 CTA、表格行下方操作按钮等。

两种常见 row + 按钮的 DOM 关系：

**类型 A：按钮在 row 内部（同一 boundingRect）**
- DOM: `<row testid=...> <text>Lista</text> <button>管理</button> </row>`
- row.querySelectorAll 能找到按钮 ✓
- dy 通常 ≈ 0（同 y 中心）
- 容差 ±30 足够

**类型 B：按钮在 row 外部独立列（不同 boundingRect）**
- DOM: `<grid> <row testid=...>Lista</row> <col2>...信息...</col2> <col3><button>管理</button></col3> </grid>`
- row.querySelectorAll 找不到按钮 ❌
- 必须 page 级 querySelector + 按 x/y 范围匹配
- dy 范围根据布局：**纯横向对齐** → dy ≈ 0；**卡片式（按钮在下方）** → dy > 0
- 必须严格区分 dy 正负，否则撞上方/下方相邻 row

**写脚本前的实探模板**：
```js
const probe = await page.evaluate(() => {
  const row = document.querySelector('[data-testid="target-row"]');
  const innerBtns = [...row.querySelectorAll('span, div, button')].filter(el =>
    el.textContent?.trim() === '管理' && el.children.length === 0);
  return {
    innerCount: innerBtns.length,
    rowRect: row.getBoundingClientRect(),
    // 全页所有「管理」按钮 + 它们距 row 的 dy
  };
});
```

如果 `innerCount > 0` 就是类型 A，否则类型 B。

**触发场景**：写任何「在列表行附近找按钮」的脚本前；定位失败先实探 DOM 关系再调容差。

本会话踩过：DEFI-LISTA-006 跑完所有 step ✓（包括 "等签名弹窗 → 点确认"），但实际签名 modal 还在屏幕上没关。

**根因**：旧版 clickModalConfirm 点完按钮立刻 return true，没验证：
1. 是否真的点到 modal 内的「确认」按钮（可能 querySelector 取的是底层 modal）
2. 点击后 modal 状态是否变化（关闭/切换）

**正确模板**：
```js
async function clickModalConfirm(page, timeoutMs = 10000) {
  const start = Date.now();
  while (Date.now() - start < timeoutMs) {
    // 1. 取**顶层** modal（最后一个，不是 querySelector 的第一个）
    const before = await page.evaluate(() => {
      const modals = [...document.querySelectorAll('[data-testid="APP-Modal-Screen"]')];
      const top = modals[modals.length - 1];
      // ... 找 top modal 内的 page-footer-confirm 或 text='确认'
      return { modalCount, topSig, pickPos };
    });
    if (!before.pickPos) { await sleep(400); continue; }

    // 2. 点击
    await page.mouse.click(before.pickPos.x, before.pickPos.y);
    await sleep(600);

    // 3. 验证 modal count 或顶层 signature 变化
    const after = await page.evaluate(() => {
      const modals = [...document.querySelectorAll('[data-testid="APP-Modal-Screen"]')];
      return { modalCount: modals.length, topSig: modals.at(-1)?.textContent.slice(0, 80) };
    });
    const stateChanged = after.modalCount !== before.modalCount || after.topSig !== before.topSig;
    if (stateChanged) return { clicked: true, ...delta };

    // 4. 没变化 → 下一轮 retry
    await sleep(500);
  }
  throw new Error('clickModalConfirm 超时');
}
```

**关键**：点击 + 验证 + retry 三件套缺一不可。

**通用原则**：所有「触发后会改变 UI 状态」的操作（modal 关闭、tab 切换、URL 跳转、文本变化）都要**点击后立即验证状态变化**，不能点完就走。

**触发场景**：所有 modal 内确认按钮 / 签名弹窗 / 任何需要广播效果的点击。

症状：签名 modal 内的「确认」按钮（BUTTON testid=page-footer-confirm）visible，但 page.mouse.click 没生效（modal 状态不变），Playwright locator.click 超时（actionability check 失败）。

根因：OneKey 用 `[data-testid="app-modal-stacks-backdrop"]` 全屏 1436×778 backdrop 在 modal 之上。坐标击中 backdrop → 不触发 BUTTON 的 click 事件。

**唯一可靠方式**：直接调用 `BUTTON.click()`（DOM API，绕过 hit-test）。BUTTON 是 HTMLButtonElement，有 click() 方法（跟 K-115 提到的 SVG 不同）。

```js
await page.evaluate(() => {
  const modals = [...document.querySelectorAll('[data-testid="APP-Modal-Screen"]')];
  const top = modals[modals.length - 1];
  const btns = [...top.querySelectorAll('[data-testid="page-footer-confirm"]')];
  btns.sort((a, b) => b.getBoundingClientRect().y - a.getBoundingClientRect().y);
  btns[0].click();  // 直接 BUTTON.click()，绕过 backdrop
});
```

**注意**：
- HTMLButtonElement.click() 有效，但 SVGElement.click() 无效（K-115）— 必须先判 tag
- 如果元素 onclick 是空、依赖 React 合成事件 — 需要 dispatchEvent('click', {bubbles:true})
- BUTTON.click() 后再走 Playwright 路径（hit-test）作为 fallback

**触发场景**：所有 OneKey 签名/授权 modal 内的 footer 按钮点击；其他被 backdrop 遮挡的场景。

症状：签名 modal 弹出后，「确认」按钮（BUTTON testid=page-footer-confirm）看起来已经显示（黑色），但所有点击方法（page.mouse.click / BUTTON.click() / dispatchEvent / Playwright force click）都不触发。

根因：modal 内的「确认」初始是 disabled 状态：
- `btn.disabled === true`
- `btn.getAttribute('aria-disabled') === 'true'`
- `window.getComputedStyle(btn).opacity === '0.4'`

OneKey 在等链上预检完成（gas 估算 / nonce 获取 / contract simulate）才会 enable 按钮。

**修复模板**（在点击前必须先等 enable）：
```js
let info;
while (Date.now() - start < timeoutMs) {
  info = await page.evaluate(() => {
    const btn = ...;
    const cs = window.getComputedStyle(btn);
    return {
      disabled: btn.disabled || btn.getAttribute('aria-disabled') === 'true',
      opacity: parseFloat(cs.opacity),
    };
  });
  if (!info.disabled && info.opacity > 0.5) break;
  await sleep(500);
}
if (info.disabled) throw new Error('按钮一直 disabled');
// 然后才点击
```

**typical timeout**: 设 30s（链上预检可能慢）。

**触发场景**：所有签名 modal 的确认按钮、Swap 报价加载后的「兑换」按钮、转账「下一步」按钮等。

症状：签名「确认」按钮点击后弹出「输入密码」modal，但 `handlePasswordPromptIfPresent` 返回 `{ handled: false, type: null }` — 没识别为 password_dialog。

根因：`handlePasswordPrompt` (components.mjs) 的密码弹窗判定要求：
```js
const inModal = input.closest('[data-testid="APP-Modal-Screen"], [role="dialog"]');
const inFixedForm = input.closest('form[style*="fixed"], form[style*="z-index"]');
if (inModal || inFixedForm) return { type: 'password_dialog' };
```

但 OneKey 密码 input 的祖先链上**没有这些容器**（CDP 实证：从 input 一直往上到 body 没有任何 testid）。

**修复模板（推荐）**：直接用 password-input visibility 判定，不依赖容器：
```js
const pwdVisible = await page.evaluate(() => {
  const inp = document.querySelector('[data-testid="password-input"]');
  if (!inp) return false;
  const r = inp.getBoundingClientRect();
  return r.width > 0 && r.height > 0;
});
if (pwdVisible) {
  await page.locator('[data-testid="password-input"]').first().fill(walletPassword);
  await page.evaluate(() => {
    document.querySelector('[data-testid="verifying-password"]')?.click();
  });
}
```

**应该修复 handlePasswordPrompt** (TODO)：把容器判定改成更宽松（只要 `r.width > 0 && r.height > 0` + type=password 或 testid=password-input 即可），让所有调用方都受益。

**触发场景**：所有签名相关测试，特别是 DeFi 质押/赎回、Swap、Transfer 触发的密码二次验证。

CDP 实测发现：
- Iter 0 调用 `BUTTON.click()` + dispatchEvent — 完全没生效（button 状态不变）
- Iter 1 再次调用 — button 立刻变 disabled（React 处理了点击 → 进入等待状态）

根因：React Native Web 的 Pressable 有 onResponderRelease 等响应链，第一次 click 可能 React event listener 还在 mount 阶段，调用了但没处理。第二次调用就正常了。

**修复模板**：
```js
// 连续点 N 次直到检测到「真实响应」
for (let i = 0; i < 5; i++) {
  await tryClick();
  await sleep(1500);
  const cur = await page.evaluate(() => ({
    modalCount: ...,
    btnDisabled: ...,
    pwdVisible: ...,
  }));
  // 任何状态变化 = click 已触发响应
  if (cur.modalCount !== before.modalCount || cur.btnDisabled === true || cur.pwdVisible) break;
}
```

**响应信号优先级**（按可靠性）：
1. ✅ modal count 减少（modal 真关）
2. ✅ button.disabled 从 false → true（点击触发了 React 处理）
3. ✅ 密码 modal 出现（触发了二次验证）
4. ❌ textContent 变化（不可靠，K-141）

**触发场景**：所有 RN Web 的 Pressable / Button 点击；OneKey 签名/Swap/Transfer 等所有需要可靠点击的场景。

**症状**：OneKey 签名 modal 的「确认」按钮 (data-testid=page-footer-confirm) 在 CDP 里 disabled=false, opacity=1, pointer-events=auto, stack 顶层就是 SPAN→BUTTON 自身（无 backdrop），但是：
- BUTTON.click() 无反应
- dispatchEvent(MouseEvent('click')) 无反应  
- dispatchEvent(pointerdown/mousedown/pointerup/mouseup/click) 无反应
- page.mouse.click(cx, cy) 无反应（含 hover 预热 mouse.move 也不行）
- Playwright locator.click({force: true}) 无反应
- focus + Enter 无反应
- modalCount / btnDisabled / pwdVisible 状态完全不变

**根因**：React Native Web 的 Pressable 组件用 PressResponder 而非原生 onClick。DOM 上的 click 事件不会触发其 onPress 回调；事件处理函数挂在外层 DIV 的 __reactProps 上（不是 BUTTON 上）。

**唯一可靠解法**：从 BUTTON 向上遍历 ancestors，找到第一个 `__reactProps$<hash>` 上有 `onClick / onPress / onResponderRelease` 的元素，直接调用：
```js
let cur = btn;
while (cur && cur.tagName !== 'BODY') {
  const propsKey = Object.keys(cur).find(k => k.startsWith('__reactProps'));
  if (propsKey) {
    const props = cur[propsKey];
    const fakeEv = { type: 'click', target: btn, currentTarget: cur,
                     clientX: cx, clientY: cy,
                     preventDefault(){}, stopPropagation(){},
                     nativeEvent: { type: 'click', target: btn } };
    for (const h of ['onClick', 'onPress', 'onResponderRelease']) {
      if (typeof props?.[h] === 'function') { props[h](fakeEv); return; }
    }
  }
  cur = cur.parentElement;
}
```

**预防**：所有 RN Web 应用（OneKey 桌面端 / web 端）的关键按钮点击，先尝试原生事件 → 失败后必须有 reactProps 兜底，不能只靠 page.mouse.click。

**实现位置**：src/tests/desktop/defi/lista-usdt.test.mjs clickModalConfirm tryClick 函数。

**问题**：插件端测试需要 Chrome 跑 CDP 模式，但每个 QA 本地启 Chrome 时端口可能不一样（有人 9224、有人 9229、有人 9301...）。如果脚本硬编码 `EXT_CDP_URL = http://127.0.0.1:9224`，换人就连不上。

**解决方案**：扫 Chrome 进程命令行参数取真实端口。

**关键过滤规则**（必须同时满足）：
1. `line.includes('Google Chrome')` — 排除 OneKey/Chromium/Edge 等其他基于 Chromium 的应用
2. `!line.includes('--type=')` — 排除 renderer/GPU/utility 等子进程（它们也带 port 参数）
3. excludePorts 排除已知 desktop(9222) / web(9223) 端口，避免误把 Web 端 Chrome 当成插件端

**实现**（`src/tests/helpers/extension-cdp.mjs`）：
```js
export function detectChromeCdpPort(excludePorts = [9222, 9223]) {
  try {
    const out = execSync('ps -axo command', { encoding: 'utf-8' });
    for (const line of out.split('\n')) {
      if (!line.includes('Google Chrome')) continue;
      if (line.includes('--type=')) continue;
      const m = line.match(/--remote-debugging-port=(\d+)/);
      if (!m) continue;
      const port = parseInt(m[1], 10);
      if (excludePorts.includes(port)) continue;
      return port;
    }
  } catch {}
  return null;
}
```

**优先级**（getCdpUrl）：
1. `EXT_CDP_URL` env（用户显式指定）
2. `detectChromeCdpPort()` 扫描结果
3. 默认 9224（首次启动 Chrome 用的端口）

**Dashboard 也要用**：`/api/cdp-status` 动态 import 这个 helper，把真实 port 随状态返回前端，前端不再硬编码端口映射。

**触发场景**：跨人协作的插件端用例 / Dashboard CDP 状态展示。

**触发场景**：DeFi 认购金额过小（如 0.001 USDT）时，OneKey 在认购 → 签名链路之间插入一个「交易损耗」warning modal：「按当前预估收益率计算，大约需要 N 年，收益才能弥补损失。预估网络费用: $X」+ 两个按钮「取消 / 确认」。

**症状**：
- 点完「认购」按钮后，clickModalConfirm 找不到 page-footer-confirm（该 modal 用 inline button）→ 卡死
- 或者 navigation 流程（goToListaUsdtDetail / goToDefiPortfolioTab）幂等检查 `modalCount === 0` 失败 → 走完整 nav，但 modal 又挡住后续 tab 点击 → 「所有资产 tab 未找到」类错误

**正确处理**：
```js
async function dismissTradeLossModal(page) {
  for (let attempt = 0; attempt < 3; attempt++) {
    const result = await page.evaluate(() => {
      const modals = [...document.querySelectorAll('[data-testid="APP-Modal-Screen"]')];
      const lossModal = modals.find(m => /交易损耗|弥补损失/.test(m.textContent || ''));
      if (!lossModal) return { found: false };
      for (const el of lossModal.querySelectorAll('span, div, button')) {
        if ((el.textContent || '').trim() !== '确认' || el.children.length !== 0) continue;
        const r = el.getBoundingClientRect();
        if (r.width === 0 || r.height === 0) continue;
        return { found: true, x: r.x + r.width/2, y: r.y + r.height/2 };
      }
      return { found: true, x: null };
    });
    if (!result.found) break;
    if (result.x != null) await page.mouse.click(result.x, result.y);
    await sleep(1000);
  }
}
```

**调用位置**（必须在以下场景前调用）：
1. `goToListaUsdtDetail` / `goToDefiPortfolioTab` 等 nav helper 开头 — 防止挡住幂等检查
2. `clickModalConfirm` 阶段 0 — 防止顶层 modal 不是签名 modal
3. 任何用例 Step 0（独立运行场景下，上一轮可能留下这个 modal）

**注意**：该 modal **没有** nav-header-close 按钮，常规 dismiss 流程（K-115 esc / nav-header-close）抓不到。

